      // Step 7: Verify Research Terms highlight is still on (memento restored) (UI-PKG-004)
      const restoredScripture = frame2.locator('[data-testid="scripture-pane"]');
      await expect(restoredScripture).toHaveClass(/showeverylink/, {
        timeout: 5_000,
      });

