test.describe('Enhanced Resources Journey Tests — Error Propagation', () => {
  // -----------------------------------------------------------------------
  // Journey 10: Open ER -> Navigate to missing book -> Warning banner shows
  //             -> Tab content empty -> Navigate back to valid book
  //   Spans: UI-PKG-003 (ScripturePane) -> UI-PKG-005 (WarningBanners)
  //          -> UI-PKG-006 (ResearchTabs empty)
  // -----------------------------------------------------------------------

  // @scenario BHV-411 (TS-112), BHV-401 (TS-099)
  test.fixme(
    'J-010: Navigate to missing book, verify warning banner and empty tabs',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Verify no missing book warning initially (UI-PKG-005)
      const warningBanner = frame.locator('[data-testid="warning-banner-missing-book"]');
      await expect(warningBanner).not.toBeVisible({ timeout: 3_000 });

      // Step 3: Navigate to a book that is not in the ER
      // This would be done via scroll group sync or book selector.
      // For NT-only ERs, navigating to an OT book would trigger this.
      // We simulate by changing the reference to an OT book if ER is NT-only.
      // Since we navigate via UI, we would use the book selector or scroll group.
      // For the test, we look for a book navigation control.
      const bookSelector = frame.locator('[data-testid="book-selector"]');
      const bookSelectorCount = await bookSelector.count();
      if (bookSelectorCount > 0) {
        // Try to select a book not in the ER (e.g., Genesis for NT-only ER)
        await bookSelector.click();
        // The actual book navigation depends on implementation
      }

      // Step 4: If missing book banner appears, verify it (UI-PKG-005)
      // This tests the cross-WP flow: scripture pane detects missing book ->
      // warning banner renders
      const hasMissingBookBanner =
        (await warningBanner.count()) > 0 && (await warningBanner.isVisible().catch(() => false));

      if (hasMissingBookBanner) {
        // Step 5: Verify banner text mentions the book name
        await expect(warningBanner).toContainText(/does not exist/i);

        // Step 6: Verify research tabs show no content (UI-PKG-006)
        const dictEntries = frame.locator('[data-testid="dictionary-entry"]');
        await expect(dictEntries).toHaveCount(0, { timeout: 5_000 });

        // Step 7: Tab icons should show disabled state
        const dictTabIcon = frame.locator('[data-testid="tab-icon-dictionary"]');
        await expect(dictTabIcon).toHaveAttribute('aria-disabled', 'true');
      }

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-010-missing-book-error.png',
      });
    },
  );

  // -----------------------------------------------------------------------
  // Journey 11: Open ER -> Click linked word -> Clear filter via X button
  //             -> Tabs reload with unfiltered content
  //   Spans: UI-PKG-003 (ScripturePane) -> UI-PKG-004 (ERToolbar filter)
  //          -> UI-PKG-006 (ResearchTabs)
  // -----------------------------------------------------------------------

  // @scenario BHV-414 (TS-118), BHV-419 (TS-123), BHV-403
  test.fixme(
    'J-011: Apply word filter then clear, verify tabs reload unfiltered',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Click a linked word to activate filter (UI-PKG-003)
      const scripturePane = frame.locator('[data-testid="scripture-pane"]');
      const linkedWord = scripturePane.locator('.linked-word').first();
      await expect(linkedWord).toBeVisible({ timeout: 10_000 });
      await linkedWord.click();

      // Step 3: Verify filter bar appears (UI-PKG-004)
      const filterBar = frame.locator('[data-testid="filter-bar"]');
      await expect(filterBar).toBeVisible({ timeout: 5_000 });

      // Step 4: Verify clear filter button (X) is visible
      const clearFilterButton = frame.locator('[data-testid="clear-filter-button"]');
      await expect(clearFilterButton).toBeVisible();

      // Step 5: Click clear filter button (UI-PKG-004)
      await clearFilterButton.click();

      // Step 6: Verify filter bar is hidden or empty (UI-PKG-004)
      await expect(filterBar).not.toBeVisible({ timeout: 5_000 });

      // Step 7: Verify research tabs reload with unfiltered content (UI-PKG-006)
      // Dictionary tab should show all entries for current scope, not filtered
      const dictTab = frame.locator('[data-testid="dictionary-tab"]');
      await expect(dictTab).toBeVisible({ timeout: 10_000 });

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-011-clear-filter-flow.png',
      });
    },
  );
});

// ===========================================================================
// OVERLAY TRANSITIONS
// Journeys that verify overlay lifecycle between work packages.
// ===========================================================================

test.describe('Enhanced Resources Journey Tests — Overlay Transitions', () => {
  // -----------------------------------------------------------------------
  // Journey 12: Open ER -> Encyclopedia tab -> Click entry -> ArticleViewer
  //             -> Click inline image -> MediaViewer replaces ArticleViewer
  //             -> Close MediaViewer -> Returns to tab list (not article)
  //   Spans: UI-PKG-006 -> UI-PKG-009 -> UI-PKG-008 -> UI-PKG-006
  //   Tests: Overlay replacement rule from interaction map
  // -----------------------------------------------------------------------

  // @scenario BHV-304, BHV-607, BHV-305, BHV-406
  test.fixme(
    'J-012: ArticleViewer to MediaViewer overlay replacement, close returns to tab list',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Switch to Encyclopedia tab (UI-PKG-006)
      const encyclopediaTabIcon = frame.locator('[data-testid="tab-icon-encyclopedia"]');
      await encyclopediaTabIcon.click();

      // Step 3: Click an encyclopedia entry to open ArticleViewer (UI-PKG-009)
      const entryRow = frame.locator('[data-testid="encyclopedia-entry"]').first();
      await expect(entryRow).toBeVisible({ timeout: 10_000 });
      await entryRow.click();

      const articleViewer = frame.locator('[data-testid="article-viewer"]');
      await expect(articleViewer).toBeVisible({ timeout: 10_000 });

      // Step 4: Look for inline images in article content
      const inlineImage = articleViewer.locator('[data-testid="article-inline-image"]').first();
      const imageCount = await inlineImage.count();

      if (imageCount > 0) {
        // Step 5: Click inline image -- ArticleViewer replaced by MediaViewer (UI-PKG-008)
        await inlineImage.click();

        const mediaViewer = frame.locator('[data-testid="media-viewer"]');
        await expect(mediaViewer).toBeVisible({ timeout: 10_000 });

        // Step 6: Verify ArticleViewer is no longer visible (replaced by MediaViewer)
        await expect(articleViewer).not.toBeVisible();

        // Step 7: Close MediaViewer
        const mediaClose = mediaViewer.locator('[data-testid="media-close-button"]');
        await mediaClose.click();

        // Step 8: Per interaction map, closing MediaViewer returns to tab list
        // (NOT back to ArticleViewer)
        await expect(mediaViewer).not.toBeVisible({ timeout: 5_000 });
        await expect(articleViewer).not.toBeVisible({ timeout: 3_000 });

        // Encyclopedia tab list should be visible again
        const encyclopediaTab = frame.locator('[data-testid="encyclopedia-tab"]');
        await expect(encyclopediaTab).toBeVisible({ timeout: 10_000 });
      } else {
        // No inline images -- close article viewer directly
        const closeButton = articleViewer.locator('[data-testid="article-close-button"]');
        await closeButton.click();
        await expect(articleViewer).not.toBeVisible({ timeout: 5_000 });
      }

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-012-overlay-replacement.png',
      });
    },
  );

  // -----------------------------------------------------------------------
  // Journey 13: Open ER -> Click word -> Filter active -> Click in
  //             scripture empty area -> Filter clears -> Tabs reload
  //   Spans: UI-PKG-003 (ScripturePane click-clear) -> UI-PKG-004
  //          (filter state) -> UI-PKG-006 (ResearchTabs reload)
  //   Tests: BHV-419 click-to-clear interaction across WPs
  // -----------------------------------------------------------------------

  // @scenario BHV-419 (TS-123), BHV-414 (TS-118), BHV-402
  test.fixme(
    'J-013: Click empty area in scripture while filtered clears filter and reloads tabs',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Click a linked word to activate filter (UI-PKG-003)
      const scripturePane = frame.locator('[data-testid="scripture-pane"]');
      const linkedWord = scripturePane.locator('.linked-word').first();
      await expect(linkedWord).toBeVisible({ timeout: 10_000 });
      await linkedWord.click();

      // Step 3: Verify filter is active (UI-PKG-004)
      const filterBar = frame.locator('[data-testid="filter-bar"]');
      await expect(filterBar).toBeVisible({ timeout: 5_000 });

      // Step 4: Click in scripture pane on non-linked area (UI-PKG-003)
      // Click on the scripture pane container itself (not on a linked word)
      await scripturePane.click({ position: { x: 10, y: 10 } });

      // Step 5: Verify filter is cleared (UI-PKG-004)
      await expect(filterBar).not.toBeVisible({ timeout: 5_000 });

      // Step 6: Verify tabs reload with unfiltered content (UI-PKG-006)
      const dictTab = frame.locator('[data-testid="dictionary-tab"]');
      await expect(dictTab).toBeVisible({ timeout: 10_000 });

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-013-click-clear-filter.png',
      });
    },
  );

  // -----------------------------------------------------------------------
  // Journey 14: Open ER -> ArticleViewer -> Click "goto verse" link ->
  //             Scripture pane navigates to new reference -> Tabs reload
  //   Spans: UI-PKG-009 (ArticleViewer goto link) -> UI-PKG-003
  //          (ScripturePane reference change) -> UI-PKG-006 (tabs reload)
  // -----------------------------------------------------------------------

  // @scenario BHV-607, BHV-417, BHV-402
  test.fixme(
    'J-014: Click goto-verse in ArticleViewer, verify scripture navigates and tabs reload',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Open Encyclopedia tab and click an entry (UI-PKG-006 -> UI-PKG-009)
      const encyclopediaTabIcon = frame.locator('[data-testid="tab-icon-encyclopedia"]');
      await encyclopediaTabIcon.click();
      const entryRow = frame.locator('[data-testid="encyclopedia-entry"]').first();
      await expect(entryRow).toBeVisible({ timeout: 10_000 });
      await entryRow.click();

      const articleViewer = frame.locator('[data-testid="article-viewer"]');
      await expect(articleViewer).toBeVisible({ timeout: 10_000 });

      // Step 3: Look for "goto verse" scripture links in article content
      const gotoLink = articleViewer.locator('[data-testid="goto-verse-link"]').first();
      const gotoCount = await gotoLink.count();

      if (gotoCount > 0) {
        // Step 4: Click goto verse link (UI-PKG-009)
        await gotoLink.click();

        // Step 5: Verify scripture pane navigates (UI-PKG-003)
        // The article viewer should close (or the reference should change)
        // and scripture should scroll to the target verse.
        const scripturePane = frame.locator('[data-testid="scripture-pane"]');
        await expect(scripturePane).toBeVisible({ timeout: 10_000 });

        // Step 6: Research tabs should reload with content for new reference (UI-PKG-006)
        const dictEntries = frame.locator('[data-testid="dictionary-entry"]');
        await expect(dictEntries.first()).toBeVisible({ timeout: 15_000 });
      }

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-014-goto-verse-from-article.png',
      });
    },
  );
});

