test.describe('Enhanced Resources Journey Tests — Scope and Filter Interaction', () => {
  // -----------------------------------------------------------------------
  // Journey 15: Open ER -> Click word -> Filter active -> Scope changes
  //             to "Current Sense" option -> Dictionary shows sense-scoped
  //   Spans: UI-PKG-003 (word click) -> UI-PKG-004 (scope with Current
  //          Sense option) -> UI-PKG-006 (filtered dictionary)
  // -----------------------------------------------------------------------

  // @scenario BHV-402 (TS-101), BHV-403, BHV-401
  test.fixme(
    'J-015: Click word, change scope to Current Sense, verify dictionary shows sense-scoped entries',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Click a linked word to activate filter (UI-PKG-003)
      const scripturePane = frame.locator('[data-testid="scripture-pane"]');
      const linkedWord = scripturePane.locator('.linked-word').first();
      await expect(linkedWord).toBeVisible({ timeout: 10_000 });
      await linkedWord.click();

      // Step 3: Verify filter bar is active (UI-PKG-004)
      const filterBar = frame.locator('[data-testid="filter-bar"]');
      await expect(filterBar).toBeVisible({ timeout: 5_000 });

      // Step 4: Open scope dropdown -- "Current Sense" should now be available
      const scopeDropdown = frame.locator('[data-testid="scope-filter"]');
      await scopeDropdown.click();
      const currentSenseOption = frame.getByRole('option', {
        name: /Current Sense/i,
      });
      await expect(currentSenseOption).toBeVisible({ timeout: 5_000 });

      // Step 5: Select Current Sense (UI-PKG-004)
      await currentSenseOption.click();

      // Step 6: Verify dictionary tab updates with sense-scoped content (UI-PKG-006)
      const dictTab = frame.locator('[data-testid="dictionary-tab"]');
      await expect(dictTab).toBeVisible({ timeout: 10_000 });
      // Dictionary should show entries scoped to the current sense
      const dictEntries = frame.locator('[data-testid="dictionary-entry"]');
      await expect(dictEntries.first()).toBeVisible({ timeout: 10_000 });

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-015-current-sense-scope.png',
      });
    },
  );

  // -----------------------------------------------------------------------
  // Journey 16: Open ER -> Maps tab -> Click map thumbnail -> MediaViewer
  //             with map image -> Close -> Return to Maps tab
  //   Spans: UI-PKG-006 (ResearchTabs/Maps) -> UI-PKG-008 (MediaViewer)
  //          -> UI-PKG-006 (back)
  //   Tests: Maps tab is separate from Media but uses same MediaViewer
  // -----------------------------------------------------------------------

  // @scenario BHV-305 (TS-083), BHV-307, BHV-406
  test.fixme(
    'J-016: Click map thumbnail, verify MediaViewer shows map, close returns to Maps tab',
    async ({ mainPage }) => {
      await waitForAppReady(mainPage);

      // Step 1: Open ER (UI-PKG-001)
      const frame = await openEnhancedResource(mainPage);
      await expect(frame.locator('[data-testid="er-web-view"]')).toBeVisible({
        timeout: 15_000,
      });

      // Step 2: Switch to Maps tab (UI-PKG-006)
      const mapsTabIcon = frame.locator('[data-testid="tab-icon-maps"]');
      await mapsTabIcon.click();
      const mapsTab = frame.locator('[data-testid="maps-tab"]');
      await expect(mapsTab).toBeVisible({ timeout: 10_000 });

      // Step 3: Click a map thumbnail (UI-PKG-006)
      const mapThumbnail = frame.locator('[data-testid="map-thumbnail"]').first();
      const mapCount = await mapThumbnail.count();

      if (mapCount > 0) {
        await mapThumbnail.click();

        // Step 4: Verify MediaViewer opens with map image (UI-PKG-008)
        const mediaViewer = frame.locator('[data-testid="media-viewer"]');
        await expect(mediaViewer).toBeVisible({ timeout: 10_000 });

        const displayedImage = mediaViewer.locator('[data-testid="media-display"]');
        await expect(displayedImage).toBeVisible({ timeout: 10_000 });

        // Step 5: Close MediaViewer
        const closeButton = mediaViewer.locator('[data-testid="media-close-button"]');
        await closeButton.click();

        // Step 6: Verify return to Maps tab (not Media tab)
        await expect(mapsTab).toBeVisible({ timeout: 10_000 });
        await expect(mediaViewer).not.toBeVisible();
      }

      // Evidence
      await mainPage.screenshot({
        path: 'e2e-tests/test-results/journey/JEVD-016-maps-media-viewer.png',
      });
    },
  );
});
